const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const p = body.profile || {};
const i9 = body.i9Context || {};
const imgLen = (body.imageBase64 || '').length;

console.log('\n======== I-9 DOCUMENT INTAKE ========');
console.log('[I9] requestId=' + (body.requestId || 'MISSING'));
console.log('[I9] immigrationStatus=' + (i9.citizenshipStatus || 'MISSING'));
console.log('[I9] documentPath=' + (i9.documentPath || 'MISSING'));
console.log('[I9] expectedList=' + (i9.expectedList || 'MISSING'));
console.log('[I9] expectedDocId=' + (i9.expectedDocId || 'MISSING'));
console.log('[I9] expectedDocLabel=' + (i9.expectedDocLabel || 'MISSING'));
console.log('[I9] selectedDocumentType=' + (body.selectedDocumentType || 'MISSING'));
console.log('[I9] documentSide=' + (body.documentSide || 'MISSING'));
console.log('[I9] profile: firstName=' + (p.legalFirstName || 'MISSING') + ' lastName=' + (p.legalLastName || 'MISSING') + ' DOB=' + (p.dateOfBirth || 'MISSING'));
console.log('[I9] imageBase64 length=' + imgLen + ' chars (~' + Math.round(imgLen * 0.75 / 1024) + ' KB)');
console.log('=====================================\n');

const allowedTypes = ['drivers-license','state-id','passport','passport-card','permanent-resident-card','employment-authorization-card','military-id','unknown'];
const allowedSides = ['front','back'];
const missing = [];
for (const path of ['requestId','selectedDocumentType','documentSide','imageBase64','profile.legalFirstName','profile.legalLastName','profile.dateOfBirth']) {
  const val = path.split('.').reduce((o, k) => (o && o[k] !== undefined ? o[k] : undefined), body);
  if (val === undefined || val === null || val === '') missing.push(path);
}
if (!i9.citizenshipStatus) missing.push('i9Context.citizenshipStatus');
if (!i9.expectedList) missing.push('i9Context.expectedList');
if (!i9.expectedDocLabel) missing.push('i9Context.expectedDocLabel');

const invalid = [];
if (body.selectedDocumentType && !allowedTypes.includes(body.selectedDocumentType)) invalid.push('selectedDocumentType');
if (body.documentSide && !allowedSides.includes(body.documentSide)) invalid.push('documentSide');

if (missing.length || invalid.length) {
  console.log('[I9] REJECTED: missing=' + JSON.stringify(missing) + ' invalid=' + JSON.stringify(invalid));
  return [{ json: { valid: false, response: { success: false, requestId: body.requestId || null, error: { code: 'INVALID_REQUEST', message: 'Missing or invalid fields.', missing, invalid }, analysis: null } } }];
}
console.log('[I9] VALID - proceeding');
return [{ json: { ...body, valid: true } }];

const input = $json;
const raw = String(input.imageBase64 || '');
const match = raw.match(/^data:(.*?);base64,(.*)$/);
const mimeType = match ? (match[1] || 'image/png') : 'image/png';
const base64 = match ? match[2] : raw;
const extByMime = { 'image/jpeg': 'jpg', 'image/jpg': 'jpg', 'image/png': 'png', 'image/webp': 'webp' };
const ext = extByMime[mimeType] || 'png';
const fileName = `${input.requestId}-i9-${input.i9Context?.expectedList || 'doc'}-${input.documentSide}.${ext}`;
const buffer = Buffer.from(base64, 'base64');
if (!buffer.length) throw new Error('imageBase64 decoded to empty buffer');
const binary = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);
return [{
  json: {
    ...input,
    mimeType,
    fileName,
    imageDataUrl: raw.startsWith('data:') ? raw : `data:${mimeType};base64,${base64}`
  },
  binary: { image: binary, data: binary }
}];

const request = $items('Convert I9 Image To Binary')[0].json;
const upload = $json;
const s3Bucket = 'instawork-prod-ops-w2-i9-docs-dev';
const s3Key = upload.key || upload.Key || 'i9/' + request.requestId + '/' + (request.fileName || 'unknown');
const s3FileUrl = 'https://' + s3Bucket + '.s3.us-west-2.amazonaws.com/' + encodeURIComponent(s3Key).replace(/%2F/g, '/');
const p = request.profile || {};
const i9 = request.i9Context || {};

console.log('[I9-PREPARE] requestId=' + request.requestId);
console.log('[I9-PREPARE] s3Key=' + s3Key);
console.log('[I9-PREPARE] s3FileUrl=' + s3FileUrl);
console.log('[I9-PREPARE] expectedList=' + i9.expectedList + ' expectedDoc=' + i9.expectedDocLabel);
console.log('[I9-PREPARE] citizenshipStatus=' + i9.citizenshipStatus);
console.log('[I9-PREPARE] selectedDocumentType=' + request.selectedDocumentType);

const binItem = $items('Convert I9 Image To Binary')[0].binary || {};
const imgBin = binItem.image || binItem.data || null;
return [{
  json: {
    requestId: request.requestId,
    selectedDocumentType: request.selectedDocumentType,
    documentSide: request.documentSide,
    mimeType: request.mimeType,
    fileName: request.fileName,
    imageDataUrl: request.imageDataUrl,
    s3FileKey: s3Key,
    s3FileUrl,
    profile: {
      legalFirstName: p.legalFirstName || '',
      legalMiddleName: p.legalMiddleName || '',
      legalLastName: p.legalLastName || '',
      dateOfBirth: p.dateOfBirth || ''
    },
    i9Context: {
      citizenshipStatus: i9.citizenshipStatus || '',
      documentPath: i9.documentPath || '',
      expectedList: i9.expectedList || '',
      expectedDocId: i9.expectedDocId || '',
      expectedDocLabel: i9.expectedDocLabel || ''
    }
  },
  binary: imgBin ? { image: imgBin, data: imgBin } : undefined
}];

const error = $input.first().json;
console.log('[I9-FALLBACK] Primary Gemini 2.5 Flash failed: ' + JSON.stringify(error?.message || error?.error || 'unknown'));
console.log('[I9-FALLBACK] Routing to gemini-2.5-pro...');

const contextItem = $('Prepare I9 Context').item;
const imgBin = contextItem.binary?.image || contextItem.binary?.data || null;

return [{
  json: { ...contextItem.json, _fallbackReason: String(error?.message || error?.error || 'Primary model unavailable') },
  binary: imgBin ? { image: imgBin, data: imgBin } : undefined
}];

const context = $('Prepare I9 Context').item.json;
const rawAnalysis = $input.first().json;
const i9 = context.i9Context || {};

console.log('[I9-FORMAT] Raw keys: ' + Object.keys(rawAnalysis).join(', '));
console.log('[I9-FORMAT] typeof text: ' + typeof rawAnalysis.text);

function extractJSON(raw) {
  if (raw.documentDetected !== undefined) return raw;
  const candidates = [
    raw.text,
    raw.content?.parts?.[0]?.text,
    raw.output_text,
    typeof raw.message === 'string' ? raw.message : null
  ];
  for (const candidate of candidates) {
    if (typeof candidate !== 'string') continue;
    const cleaned = candidate.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
    console.log('[I9-PARSE] Trying candidate, first 200 chars: ' + cleaned.substring(0, 200));
    try { return JSON.parse(cleaned); } catch(e) { console.log('[I9-PARSE] Failed: ' + e.message); }
  }
  return null;
}

function toFieldMatch(val) {
  if (!val) return { status: 'NOT_CHECKED' };
  if (typeof val === 'string') {
    const s = val.toUpperCase();
    return { status: ['MATCH','MISMATCH','PARTIAL_MATCH','AMBIGUOUS','NOT_CHECKED'].includes(s) ? s : 'NOT_CHECKED' };
  }
  if (typeof val === 'object') {
    const s = String(val.status || 'NOT_CHECKED').toUpperCase();
    return {
      status: ['MATCH','MISMATCH','PARTIAL_MATCH','AMBIGUOUS','NOT_CHECKED'].includes(s) ? s : 'NOT_CHECKED',
      details: val.details || null,
      userProvided: val.userProvided || null,
      documentExtracted: val.documentExtracted || null
    };
  }
  return { status: 'NOT_CHECKED' };
}

function toFlag(f) {
  if (typeof f === 'string') return { severity: 'CRITICAL', code: f, message: f.replace(/_/g, ' ').toLowerCase() };
  return { severity: f.severity || 'CRITICAL', code: f.code || 'UNKNOWN', message: f.message || f.code || 'Unknown issue' };
}

const a = extractJSON(rawAnalysis);

if (!a) {
  console.log('[I9-RESULT] PARSE FAILED — returning friendly error');
  return [{ json: {
    success: false, requestId: context.requestId, source: 'n8n-i9-gemini',
    s3FileKey: context.s3FileKey || null,
    s3FileUrl: context.s3FileUrl || null,
    userMessage: 'We could not verify this image automatically. Please retake the photo with good lighting and ensure the full document is visible.',
    analysis: {
      documentDetected: false, detectedDocumentType: 'unknown', detectedDocumentTypeLabel: 'Unknown',
      documentTypeMatch: false, userSelectedType: context.selectedDocumentType || 'unknown',
      userSelectedTypeLabel: 'Unknown', detectedSide: context.documentSide || 'front',
      sideMatchesSelected: false, extractedFields: {},
      validationResults: {
        nameMatch: { status: 'NOT_CHECKED' }, dobMatch: { status: 'NOT_CHECKED' },
        addressMatch: { status: 'NOT_CHECKED' }, expirationStatus: 'UNKNOWN', photoIntegrity: 'UNCLEAR'
      },
      flags: [{ severity: 'CRITICAL', code: 'ANALYSIS_FAILED', message: 'Document could not be read from the image.' }],
      complianceEligibility: false, nextAction: 'RETAKE_PHOTO',
      humanReviewRequired: true, reviewReason: 'Gemini response parse failure'
    }
  } }];
}

console.log('[I9-FORMAT] Parsed OK. documentDetected=' + a.documentDetected + ' detectedType=' + a.detectedDocumentType);

const vr = a.validationResults || {};
const ef = a.extractedFields || {};
const clm = a.crossListMismatch || {};
const isc = a.immigrationStatusCheck || {};

let flags = Array.isArray(a.flags) ? a.flags.map(toFlag) : [];

function isFutureIssueDateProblem(value) {
  const text = String(value || '').toUpperCase();
  return text.includes('ISSUE DATE') && (text.includes('FUTURE') || text.includes('NOT YET VALID') || text.includes('NOT-YET-VALID'));
}
function isFutureIssueDateFlag(f) {
  const code = String(f.code || '').toUpperCase();
  const message = String(f.message || '').toUpperCase();
  return ((code.includes('ISSUE') && code.includes('FUTURE')) || code.includes('NOT_YET_VALID') || isFutureIssueDateProblem(message));
}
const removedFutureIssueDateFlag = flags.some(isFutureIssueDateFlag);
flags = flags.filter(f => !isFutureIssueDateFlag(f));
if (removedFutureIssueDateFlag) console.log('[I9-SAFETY] Removed future issue-date flag; issue_date is informational only.');

function textMentionsEadAutoExtension(value) {
  const text = String(value || '').toUpperCase();
  return text.includes('I-797C')
    || text.includes('I797C')
    || text.includes('NOTICE OF ACTION')
    || text.includes('AUTO-EXTENSION')
    || text.includes('AUTO EXTENSION')
    || text.includes('AUTOMATIC EXTENSION')
    || text.includes('RENEWAL RECEIPT')
    || text.includes('RECEIPT NOTICE');
}
function isAutoExtendedEad() {
  const selected = String(context.selectedDocumentType || '').toLowerCase();
  const detected = String(a.detectedDocumentType || '').toLowerCase();
  const label = String(a.detectedDocumentTypeLabel || '').toUpperCase();
  const fieldsText = JSON.stringify(ef || {});
  const flagsText = JSON.stringify(flags || []);
  const isEad = selected === 'employment-authorization-card'
    || detected === 'employment-authorization-card'
    || label.includes('EMPLOYMENT AUTHORIZATION');
  return isEad && (
    textMentionsEadAutoExtension(fieldsText)
    || textMentionsEadAutoExtension(a.userMessage)
    || textMentionsEadAutoExtension(a.reviewReason)
    || textMentionsEadAutoExtension(flagsText)
  );
}
const autoExtendedEad = isAutoExtendedEad();
if (autoExtendedEad) {
  flags = flags.filter(f => String(f.code || '').toUpperCase() !== 'DOCUMENT_EXPIRED');
  if (vr && typeof vr === 'object') vr.expirationStatus = 'VALID';
  if (!flags.some(f => f.code === 'EAD_AUTO_EXTENSION')) {
    flags.push({ severity: 'INFO', code: 'EAD_AUTO_EXTENSION', message: 'This Employment Authorization Document (Form I-766) has been auto-extended with a valid Form I-797C receipt notice. The printed expiry date on the card is not enforced.' });
  }
  console.log('[I9-SAFETY] Treating expired Form I-766 as auto-extended based on matching Form I-797C / renewal receipt evidence.');
}

const i9ExpiryExceptionCodes = ['EAD_AUTO_EXTENSION', 'I551_EXTENSION_NOTICE', 'ADIT_STAMP_ACCEPTED', 'VENEZUELAN_PASSPORT_EXPIRY_BYPASS', 'RECEIPT_DOCUMENT_ACCEPTED'];
const hasExpiryException = flags.some(f => i9ExpiryExceptionCodes.includes(f.code));
if (hasExpiryException) {
  flags = flags.filter(f => String(f.code || '').toUpperCase() !== 'DOCUMENT_EXPIRED');
  if (vr && typeof vr === 'object' && (!vr.expirationStatus || vr.expirationStatus === 'EXPIRED')) {
    vr.expirationStatus = 'NOT_APPLICABLE';
  }
  console.log('[I9-SAFETY] I-9 expired document exception detected; removed DOCUMENT_EXPIRED flag.');
}

function isCopyOrScreenshotProblem(value) {
  const text = String(value || '').toUpperCase();
  return text.includes('DOCUMENT_COPY_OR_SCREENSHOT')
    || text.includes('SCREENSHOT')
    || text.includes('SCREEN CAPTURE')
    || text.includes('PHOTO OF A SCREEN')
    || text.includes('XEROX')
    || text.includes('PHOTOCOPY')
    || text.includes('SCANNED COPY')
    || text.includes('SCAN OF')
    || text.includes('PRINTED COPY')
    || text.includes('BLACK-AND-WHITE COPY')
    || text.includes('BLACK AND WHITE COPY')
    || text.includes('DIGITAL COPY');
}
function isCopyOrScreenshotFlag(f) {
  return isCopyOrScreenshotProblem(f.code) || isCopyOrScreenshotProblem(f.message);
}
const modelReportedCopyOrScreenshot = flags.some(isCopyOrScreenshotFlag) || isCopyOrScreenshotProblem(a.userMessage);
if (modelReportedCopyOrScreenshot && !flags.some(f => f.code === 'DOCUMENT_COPY_OR_SCREENSHOT')) {
  flags.push({ severity: 'CRITICAL', code: 'DOCUMENT_COPY_OR_SCREENSHOT', message: 'Document appears to be a screenshot, scan, photocopy, or xerox copy instead of the original physical document.' });
  console.log('[I9-SAFETY] Auto-injected CRITICAL DOCUMENT_COPY_OR_SCREENSHOT flag');
}
flags.forEach(f => { if (f.code === 'DOCUMENT_COPY_OR_SCREENSHOT') f.severity = 'CRITICAL'; });

if (clm.detected && !flags.some(f => f.code === 'WRONG_LIST')) {
  flags.unshift({ severity: 'CRITICAL', code: 'WRONG_LIST', message: clm.message || 'Document belongs to a different I-9 list than expected.' });
}
if (a.documentTypeMatch === false && a.listMatch === true && !flags.some(f => f.code === 'WRONG_DOCUMENT')) {
  flags.unshift({ severity: 'WARNING', code: 'WRONG_DOCUMENT', message: 'You selected "' + (i9.expectedDocLabel || '') + '" but uploaded a different document from the same list.' });
}
if (isc.documentAllowedForStatus === false && !flags.some(f => f.code === 'STATUS_INELIGIBLE')) {
  flags.unshift({ severity: 'CRITICAL', code: 'STATUS_INELIGIBLE', message: isc.reason || 'This document is not valid for your immigration status.' });
}

const rawCompliance = typeof a.complianceEligibility === 'boolean' ? a.complianceEligibility : false;
// Any CRITICAL flag must block continuation regardless of what the model returned
const hasCriticalFlag = flags.some(f => f.severity === 'CRITICAL');
const nameStatus = (typeof vr.nameMatch === 'object' && vr.nameMatch ? (vr.nameMatch.status || '') : (typeof vr.nameMatch === 'string' ? vr.nameMatch : '')).toUpperCase();
const dobStatus = (typeof vr.dobMatch === 'object' && vr.dobMatch ? (vr.dobMatch.status || '') : (typeof vr.dobMatch === 'string' ? vr.dobMatch : '')).toUpperCase();
const hasValidationMismatch = nameStatus === 'MISMATCH' || dobStatus === 'MISMATCH';
const modelMessageMentionsFutureIssueDate = isFutureIssueDateProblem(a.userMessage);
const documentDetectedCheck = Boolean(a.documentDetected);
const documentTypeMatchCheck = Boolean(a.documentTypeMatch);
const sideMatchesCheck = Boolean(a.sideMatchesSelected !== false);
const listMatchCheck = a.listMatch !== false;
const statusAllowedCheck = isc.documentAllowedForStatus !== false;
const modelRejectedOnlyForFutureIssueDate = (removedFutureIssueDateFlag || modelMessageMentionsFutureIssueDate) && documentDetectedCheck && documentTypeMatchCheck && sideMatchesCheck && listMatchCheck && statusAllowedCheck && !hasCriticalFlag && !hasValidationMismatch;
const modelRejectedOnlyForAutoExtendedEad = (autoExtendedEad) && documentDetectedCheck && documentTypeMatchCheck && sideMatchesCheck && listMatchCheck && statusAllowedCheck && !hasCriticalFlag && !hasValidationMismatch;
const modelRejectedOnlyForExpiryException = hasExpiryException && documentDetectedCheck && documentTypeMatchCheck && sideMatchesCheck && listMatchCheck && statusAllowedCheck && !hasCriticalFlag && !hasValidationMismatch;
const complianceEligibility = (rawCompliance || modelRejectedOnlyForFutureIssueDate || modelRejectedOnlyForAutoExtendedEad || modelRejectedOnlyForExpiryException) && !hasCriticalFlag && !hasValidationMismatch;

const labels = {
  'drivers-license': "US Driver's License", 'state-id': 'US State ID Card',
  'passport': 'US Passport', 'passport-card': 'US Passport Card',
  'permanent-resident-card': 'US Permanent Resident Card',
  'foreign-passport-i551-stamp': 'Foreign Passport with Temporary I-551 Stamp',
  'foreign-passport-mriv': 'Foreign Passport with Machine-Readable Immigrant Visa (MRIV)',
  'expired-green-card-i797': 'Expired Permanent Resident Card with Form I-797 Extension Notice',
  'i94-i551-stamp-photo': 'Form I-94 with I-551 Stamp and Photograph',
  'foreign-passport-i94': 'Foreign Passport with Form I-94',
  'employment-authorization-card': 'US Employment Authorization Card',
  'military-id': 'US Military ID', 'school-id': 'School ID with Photograph', 'unknown': 'Unknown Document'
};

let detectedType = a.detectedDocumentType || context.selectedDocumentType || 'unknown';
const selectedType = context.selectedDocumentType || 'unknown';

// SAFETY NET: passport book vs passport card auto-correction
if (detectedType === 'passport-card') {
  const allFieldsStr = JSON.stringify(ef).toUpperCase();
  const hasBookMRZ = allFieldsStr.includes('P<USA');
  const labelMentionsBook = (a.detectedDocumentTypeLabel || '').toUpperCase().includes('PASSPORT BOOK');
  const hasMultiplePages = allFieldsStr.includes('BOOKLET') || allFieldsStr.includes('BOOK');
  if (hasBookMRZ || labelMentionsBook || hasMultiplePages) {
    console.log('[I9-SAFETY] Auto-correcting passport-card -> passport (book cues: MRZ=' + hasBookMRZ + ' label=' + labelMentionsBook + ' pages=' + hasMultiplePages + ')');
    detectedType = 'passport';
    a.detectedDocumentType = 'passport';
    a.detectedDocumentTypeLabel = 'US Passport';
    if (selectedType === 'passport') {
      a.documentTypeMatch = true;
    }
  }
}
if (detectedType === 'passport') {
  const labelSaysCard = (a.detectedDocumentTypeLabel || '').toUpperCase().includes('PASSPORT CARD');
  if (labelSaysCard) {
    console.log('[I9-SAFETY] Label says passport card but type says passport — fixing label');
    a.detectedDocumentTypeLabel = 'US Passport';
  }
}

const normalizedAnalysis = {
  documentDetected: Boolean(a.documentDetected),
  userSelectedType: selectedType,
  userSelectedTypeLabel: labels[selectedType] || selectedType,
  detectedDocumentType: detectedType,
  detectedDocumentTypeLabel: a.detectedDocumentTypeLabel || labels[detectedType] || detectedType,
  documentTypeMatch: Boolean(a.documentTypeMatch),
  detectedSide: a.detectedSide || context.documentSide || 'front',
  sideMatchesSelected: Boolean(a.sideMatchesSelected !== false),
  extractedFields: ef,
  validationResults: {
    nameMatch: toFieldMatch(vr.nameMatch),
    dobMatch: toFieldMatch(vr.dobMatch),
    addressMatch: toFieldMatch(vr.addressMatch || 'NOT_CHECKED'),
    expirationStatus: vr.expirationStatus || 'UNKNOWN',
    photoIntegrity: vr.photoIntegrity || 'CLEAR'
  },
  flags,
  complianceEligibility,
  nextAction: modelReportedCopyOrScreenshot ? 'RETAKE_PHOTO' : (a.nextAction || (complianceEligibility ? 'CONTINUE' : 'HALT_VERIFICATION')) ,
  humanReviewRequired: Boolean(a.humanReviewRequired ?? !complianceEligibility),
  reviewReason: a.reviewReason || null
};

console.log('\n======== I-9 VERIFICATION RESULT ========');
console.log('[I9] request=' + context.requestId);
console.log('[I9] immigration=' + i9.citizenshipStatus + ' expectedList=' + i9.expectedList + ' expectedDoc=' + i9.expectedDocLabel);
console.log('[I9] detectedDoc=' + (a.detectedDocumentTypeLabel || '?') + ' actualList=' + (a.actualDocumentList || '?'));
console.log('[I9] listMatch=' + a.listMatch + ' docMatch=' + a.documentTypeMatch);
console.log('[I9] crossListMismatch=' + JSON.stringify(clm));
console.log('[I9] statusCheck=' + JSON.stringify(isc));
console.log('[I9] name=' + normalizedAnalysis.validationResults.nameMatch.status + ' dob=' + normalizedAnalysis.validationResults.dobMatch.status);
console.log('[I9] compliance=' + complianceEligibility + ' action=' + normalizedAnalysis.nextAction);
console.log('[I9] flags=' + JSON.stringify(flags));
const finalUserMessage = modelReportedCopyOrScreenshot
  ? 'Please upload a clear photo of the original physical document. Screenshots, scans, photocopies, and xerox copies cannot be accepted.'
  : (modelMessageMentionsFutureIssueDate
    ? (complianceEligibility ? 'Your document has been verified successfully.' : 'There was an issue verifying your document. Please check the details below.')
    : (a.userMessage || (complianceEligibility ? 'Your document has been verified successfully.' : 'There was an issue verifying your document. Please check the details below.')));
console.log('[I9] userMessage=' + (finalUserMessage || 'none'));
console.log('=========================================\n');

return [{ json: {
  success: true,
  requestId: context.requestId,
  source: 'n8n-i9-gemini',
  s3FileKey: context.s3FileKey || null,
  s3FileUrl: context.s3FileUrl || null,
  userMessage: finalUserMessage,
  analysis: normalizedAnalysis
} }];
